#include <stdio.h>
#include <stdlib.h>
#define INF 1000000000
#define V 100001
typedef struct { int v, w; } Edge;
typedef struct { Edge *edges; int size; } Graph;
Graph *createGraph(int V) {
    Graph *graph = (Graph *)malloc(sizeof(Graph));
    graph->edges = (Edge *)malloc(V * sizeof(Edge));
    graph->size = 0;
    return graph;
}
void addEdge(Graph *graph, int u, int v, int w) {
    graph->edges[graph->size].v = v;
    graph->edges[graph->size].w = w;
    graph->size++;
}
int *dijkstra(Graph *graph, int V, int src) {
    int *dist = (int *)malloc(V * sizeof(int));
    for (int i = 0; i < V; i++) dist[i] = INF;
    dist[src] = 0;
    // priority queue implementation
    int *pq = (int *)malloc(V * sizeof(int));
    int pqSize = 0;
    pq[pqSize++] = src;
    while (pqSize > 0) {
        int u = pq[pqSize - 1];
        pqSize--;
        for (int i = 0; i < graph->size; i++) {
            int v = graph->edges[i].v;
            int w = graph->edges[i].w;
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq[pqSize++] = v;
            }
        }
    }
    free(pq);
    return dist;
}
int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Graph *graph = createGraph(V);
    for (int i = 0; i < E; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        addEdge(graph, u, v, w);
    }
    int src;
    scanf("%d", &src);
    int *dist = dijkstra(graph, V, src);
    for (int i = 0; i < V; i++) printf("%d ", dist[i]);
    free(dist);
    free(graph->edges);
    free(graph);
    return 0;
}

