#include <queue>
#include <limits>
using namespace std;
typedef pair<int, int> pii;
const int INF = 1000000000;
const int V = 100001;
vector<pii> adj[V];
void addEdge(int u, int v, int w) {
    adj[u].push_back({v, w});
}
vector<int> dijkstra(int V, int src) {
    vector<int> dist(V, INF);
    dist[src] = 0;
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    pq.push({0, src});
    while (!pq.empty()) {
        int u = pq.top().second;
        int d = pq.top().first;
        pq.pop();
        if (d > dist[u]) continue;
        for (auto &edge : adj[u]) {
            int v = edge.first;
            int w = edge.second;
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}
