const INF = 1000000000;
const V = 100001;
function dijkstra(V, src, edges) {
    const dist = new Array(V).fill(INF);
    dist[src] = 0;
    const pq = [];
    pq.push([0, src]);
    while (pq.length > 0) {
        pq.sort((a, b) => a[0] - b[0]);
        const [d, u] = pq.shift();
        if (d > dist[u]) continue;
        for (const [v, w] of edges[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push([dist[v], v]);
            }
        }
    }
    return dist;
}
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let V, E;
let edges = [];
rl.on('line', (input) => {
    if (!V) {
        [V, E] = input.split(' ').map(Number);
        edges = new Array(V).fill(0).map(() => []);
    } else if (edges.length < E) {
        const [u, v, w] = input.split(' ').map(Number);
        edges[u - 1].push([v - 1, w]);
    } else {
        const src = Number(input) - 1;
        const dist = dijkstra(V, src, edges);
        console.log(dist.join(' '));
        rl.close();
    }
});
